import { createContext, useContext, useState, useEffect } from 'react'
import { useAuth } from './AuthContext'

const WallpaperContext = createContext(null)

export const WALLPAPERS = [
    { id: 'default', name: 'Default', path: '/bg.jpeg', thumbnail: '/bg.jpeg' },
    { id: 'high-sierra', name: 'High Sierra', path: '/wallpapers/10-13.jpeg', thumbnail: '/wallpapers/thumbnails/10-13 Small.jpeg' },
    { id: 'sequoia-dark', name: 'Sequoia Dark', path: '/wallpapers/15-Sequoia-Dark-6K.jpeg', thumbnail: '/wallpapers/thumbnails/15-Sequoia-Dark-6K Small.jpeg' },
    { id: 'sequoia-light', name: 'Sequoia Light', path: '/wallpapers/15-Sequoia-Light-6K.jpeg', thumbnail: '/wallpapers/thumbnails/15-Sequoia-Light-6K Small.jpeg' },
    { id: 'sequoia-sunrise', name: 'Sequoia Sunrise', path: '/wallpapers/15-Sequoia-Sunrise.jpeg', thumbnail: '/wallpapers/thumbnails/15-Sequoia-Sunrise Small.jpeg' },
    { id: 'tahoe-dawn', name: 'Tahoe Dawn', path: '/wallpapers/26-Tahoe-Beach-Dawn.jpeg', thumbnail: '/wallpapers/thumbnails/26-Tahoe-Beach-Dawn Small.jpeg' },
    { id: 'tahoe-day', name: 'Tahoe Day', path: '/wallpapers/26-Tahoe-Beach-Day.jpeg', thumbnail: '/wallpapers/thumbnails/26-Tahoe-Beach-Day Small.jpeg' },
    { id: 'tahoe-dusk', name: 'Tahoe Dusk', path: '/wallpapers/26-Tahoe-Beach-Dusk.jpeg', thumbnail: '/wallpapers/thumbnails/26-Tahoe-Beach-Dusk Small.jpeg' },
    { id: 'tahoe-night', name: 'Tahoe Night', path: '/wallpapers/26-Tahoe-Beach-Night.jpeg', thumbnail: '/wallpapers/thumbnails/26-Tahoe-Beach-Night Small.jpeg' },
]

export const ACCENT_COLORS = [
    { id: 'blue', label: 'Blue', value: '#007AFF' },
    { id: 'purple', label: 'Purple', value: '#AF52DE' },
    { id: 'pink', label: 'Pink', value: '#FF2D55' },
    { id: 'red', label: 'Red', value: '#FF3B30' },
    { id: 'orange', label: 'Orange', value: '#FF9500' },
    { id: 'yellow', label: 'Yellow', value: '#FFCC00' },
    { id: 'green', label: 'Green', value: '#34C759' },
    { id: 'graphite', label: 'Graphite', value: '#8E8E93' },
    { id: 'multicolor', label: 'Multicolor', value: '#007AFF' },
]

const DEFAULT_STORAGE_KEY = 'coordinator-wallpaper'
const DEFAULT_THEME_KEY = 'coordinator-theme'
const DEFAULT_ACCENT_KEY = 'coordinator-accent'

export function WallpaperProvider({ children }) {
    const { user } = useAuth()

    // Helper to get keys - memoized not strictly needed for this simple func
    const getKeys = (u) => ({
        wallpaper: u ? `coordinator-wallpaper-${u.username}` : DEFAULT_STORAGE_KEY,
        theme: u ? `coordinator-theme-${u.username}` : DEFAULT_THEME_KEY,
        accent: u ? `coordinator-accent-${u.username}` : DEFAULT_ACCENT_KEY
    })

    // Initialize state by reading storage IMMEDIATELY
    const [wallpaper, setWallpaperState] = useState(() => {
        const keys = getKeys(user)
        const saved = localStorage.getItem(keys.wallpaper)
        if (saved) {
            const found = WALLPAPERS.find(w => w.id === saved)
            if (found) return found
        }
        return WALLPAPERS[0]
    })

    const [theme, setThemeState] = useState(() => {
        const keys = getKeys(user)
        return localStorage.getItem(keys.theme) || 'dark'
    })

    const [accentColor, setAccentColorState] = useState(() => {
        const keys = getKeys(user)
        const saved = localStorage.getItem(keys.accent)
        if (saved) {
            const found = ACCENT_COLORS.find(c => c.id === saved)
            if (found) return found
        }
        return ACCENT_COLORS[0]
    })

    // Re-load settings when user changes (e.g. login/logout)
    useEffect(() => {
        const keys = getKeys(user)

        const savedWP = localStorage.getItem(keys.wallpaper)
        if (savedWP) {
            const found = WALLPAPERS.find(w => w.id === savedWP)
            if (found) setWallpaperState(found)
        } else if (!user) {
            setWallpaperState(WALLPAPERS[0])
        }

        const savedTheme = localStorage.getItem(keys.theme)
        setThemeState(savedTheme || 'dark')

        const savedAccent = localStorage.getItem(keys.accent)
        if (savedAccent) {
            const found = ACCENT_COLORS.find(c => c.id === savedAccent)
            if (found) setAccentColorState(found)
        } else {
            setAccentColorState(ACCENT_COLORS[0])
        }
    }, [user]) // Should trigger when user object updates

    const setWallpaper = (wp) => {
        setWallpaperState(wp)
        localStorage.setItem(getKeys(user).wallpaper, wp.id)
    }

    const setTheme = (t) => {
        setThemeState(t)
        localStorage.setItem(getKeys(user).theme, t)
    }

    const setAccentColor = (color) => {
        setAccentColorState(color)
        localStorage.setItem(getKeys(user).accent, color.id)
    }

    // Effects for DOM updates
    useEffect(() => {
        document.body.style.setProperty('--wallpaper-url', `url('${wallpaper.path}')`)
    }, [wallpaper])

    useEffect(() => {
        document.documentElement.setAttribute('data-theme', theme)
    }, [theme])

    useEffect(() => {
        const root = document.documentElement
        root.style.setProperty('--accent-color', accentColor.value)
        const darken = (hex, amount = 30) => {
            const num = parseInt(hex.slice(1), 16)
            const r = Math.max(0, (num >> 16) - amount)
            const g = Math.max(0, ((num >> 8) & 0x00FF) - amount)
            const b = Math.max(0, (num & 0x0000FF) - amount)
            return `#${(r << 16 | g << 8 | b).toString(16).padStart(6, '0')}`
        }
        root.style.setProperty('--accent-hover', darken(accentColor.value))
        root.style.setProperty('--accent-gradient', `linear-gradient(135deg, ${accentColor.value} 0%, ${darken(accentColor.value)} 100%)`)
    }, [accentColor])

    return (
        <WallpaperContext.Provider value={{
            wallpaper, setWallpaper, wallpapers: WALLPAPERS,
            theme, setTheme,
            accentColor, setAccentColor, accentColors: ACCENT_COLORS,
        }}>
            {children}
        </WallpaperContext.Provider>
    )
}

export const useWallpaper = () => useContext(WallpaperContext)
