import { useState, useEffect, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { useSpotlight } from '../contexts/SpotlightContext'
import { useSettings } from '../contexts/SettingsContext'
import { useNotifications } from '../contexts/NotificationContext'

/**
 * KeyboardShortcuts — Global keyboard shortcut handler
 * Renders a help overlay when ⌘/ is pressed.
 */

const SHORTCUTS = [
    { keys: ['⌘', 'K'], description: 'Spotlight Search', category: 'Navigation' },
    { keys: ['⌘', 'N'], description: 'New Note (go to Students)', category: 'Actions' },
    { keys: ['⌘', 'E'], description: 'Export Data', category: 'Actions' },
    { keys: ['⌘', ','], description: 'Open Settings', category: 'Navigation' },
    { keys: ['⌘', '/'], description: 'Keyboard Shortcuts', category: 'Help' },
    { keys: ['⌘', 'D'], description: 'Dashboard', category: 'Navigation' },
    { keys: ['⌘', 'G'], description: 'Formation Groups', category: 'Navigation' },
    { keys: ['Esc'], description: 'Close overlay / modal', category: 'General' },
]

function KeyboardShortcuts() {
    const [showHelp, setShowHelp] = useState(false)
    const navigate = useNavigate()
    const { toggleSpotlight } = useSpotlight()
    const { openSettings } = useSettings()
    const { toggleCenter } = useNotifications()

    const handleKeyDown = useCallback((e) => {
        // Don't handle if typing in an input
        const tag = e.target.tagName.toLowerCase()
        if (tag === 'input' || tag === 'textarea' || tag === 'select') return

        const isMeta = e.metaKey || e.ctrlKey

        if (isMeta && e.key === 'k') {
            e.preventDefault()
            toggleSpotlight()
            return
        }
        if (isMeta && e.key === 'n') {
            e.preventDefault()
            navigate('/students')
            return
        }
        if (isMeta && e.key === 'e') {
            e.preventDefault()
            navigate('/exports')
            return
        }
        if (isMeta && e.key === ',') {
            e.preventDefault()
            openSettings()
            return
        }
        if (isMeta && e.key === '/') {
            e.preventDefault()
            setShowHelp(prev => !prev)
            return
        }
        if (isMeta && e.key === 'd') {
            e.preventDefault()
            navigate('/dashboard')
            return
        }
        if (isMeta && e.key === 'g') {
            e.preventDefault()
            navigate('/groups')
            return
        }
        if (e.key === 'Escape' && showHelp) {
            setShowHelp(false)
            return
        }
    }, [navigate, toggleSpotlight, openSettings, showHelp, toggleCenter])

    useEffect(() => {
        window.addEventListener('keydown', handleKeyDown)
        return () => window.removeEventListener('keydown', handleKeyDown)
    }, [handleKeyDown])

    if (!showHelp) return null

    // Group shortcuts by category
    const categories = {}
    SHORTCUTS.forEach(s => {
        if (!categories[s.category]) categories[s.category] = []
        categories[s.category].push(s)
    })

    return (
        <div className="shortcuts-overlay" onClick={() => setShowHelp(false)}>
            <div className="shortcuts-modal" onClick={e => e.stopPropagation()}>
                <div className="shortcuts-header">
                    <h3>⌨️ Keyboard Shortcuts</h3>
                    <button className="shortcuts-close" onClick={() => setShowHelp(false)}>×</button>
                </div>

                <div className="shortcuts-body">
                    {Object.entries(categories).map(([cat, items]) => (
                        <div key={cat} className="shortcut-category">
                            <div className="shortcut-cat-title">{cat}</div>
                            {items.map((s, i) => (
                                <div key={i} className="shortcut-row">
                                    <span className="shortcut-desc">{s.description}</span>
                                    <span className="shortcut-keys">
                                        {s.keys.map((k, j) => (
                                            <kbd key={j}>{k}</kbd>
                                        ))}
                                    </span>
                                </div>
                            ))}
                        </div>
                    ))}
                </div>

                <div className="shortcuts-footer">
                    Press <kbd>⌘</kbd><kbd>/</kbd> to toggle this overlay
                </div>
            </div>

            <style>{`
                .shortcuts-overlay {
                    position: fixed;
                    inset: 0;
                    background: rgba(0, 0, 0, 0.4);
                    backdrop-filter: blur(20px) saturate(140%);
                    -webkit-backdrop-filter: blur(20px) saturate(140%);
                    z-index: 10002;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    animation: spotFadeIn 0.2s var(--ease-smooth);
                }
                [data-theme="light"] .shortcuts-overlay {
                    background: rgba(255, 255, 255, 0.2);
                    backdrop-filter: blur(20px) saturate(160%);
                }

                .shortcuts-modal {
                    width: 440px;
                    max-width: 90vw;
                    background: var(--glass-layer-2);
                    backdrop-filter: var(--blur-layer-2);
                    -webkit-backdrop-filter: var(--blur-layer-2);
                    border-radius: 20px;
                    border: var(--border-layer-2);
                    box-shadow: var(--shadow-layer-4);
                    overflow: hidden;
                    animation: qlScale 0.3s var(--ease-out-expo);
                    position: relative;
                }
                /* Inner rim light */
                .shortcuts-modal::after {
                    content: ''; position: absolute; inset: 0; border-radius: 20px; padding: 1px;
                    background: linear-gradient(180deg, rgba(255,255,255,0.2) 0%, transparent 100%);
                    -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
                    -webkit-mask-composite: xor; mask-composite: exclude; pointer-events: none;
                }

                .shortcuts-header {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    padding: 16px 24px 12px;
                    border-bottom: 1px solid var(--separator);
                    background: rgba(0,0,0,0.02);
                }
                .shortcuts-header h3 {
                    margin: 0;
                    font-size: 16px;
                    font-weight: 600;
                    color: var(--text-primary);
                }
                .shortcuts-close {
                    background: none;
                    border: none;
                    color: var(--text-tertiary);
                    font-size: 20px;
                    cursor: pointer;
                    padding: 4px;
                    line-height: 1;
                    width: 28px; height: 28px; border-radius: 50%;
                    display: flex; align-items: center; justify-content: center;
                    transition: all 0.2s;
                }
                .shortcuts-close:hover { background: rgba(128,128,128,0.15); color: var(--text-primary); }

                .shortcuts-body {
                    padding: 16px 24px;
                    max-height: 400px;
                    overflow-y: auto;
                }

                .shortcut-category { margin-bottom: 20px; }
                .shortcut-cat-title {
                    font-size: 11px;
                    font-weight: 700;
                    color: var(--text-tertiary);
                    text-transform: uppercase;
                    letter-spacing: 0.8px;
                    margin-bottom: 10px;
                }

                .shortcut-row {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    padding: 8px 0;
                    border-bottom: 1px solid rgba(128,128,128,0.05);
                }
                .shortcut-row:last-child { border-bottom: none; }
                
                .shortcut-desc {
                    font-size: 13px;
                    color: var(--text-secondary);
                }

                .shortcut-keys {
                    display: flex;
                    gap: 4px;
                }
                .shortcut-keys kbd {
                    background: var(--glass-layer-3);
                    border: 1px solid var(--border-layer-3);
                    padding: 2px 8px;
                    border-radius: 6px;
                    font-size: 12px;
                    font-weight: 600;
                    color: var(--text-primary);
                    font-family: 'SF Mono', 'Menlo', monospace;
                    min-width: 24px;
                    text-align: center;
                    box-shadow: 0 1px 2px rgba(0,0,0,0.1);
                }

                .shortcuts-footer {
                    padding: 12px 24px;
                    border-top: 1px solid var(--separator);
                    text-align: center;
                    font-size: 12px;
                    color: var(--text-tertiary);
                    background: rgba(0,0,0,0.01);
                }
                .shortcuts-footer kbd {
                    background: rgba(128,128,128,0.1);
                    padding: 2px 6px;
                    border-radius: 4px;
                    font-family: inherit;
                    font-size: 11px;
                    color: var(--text-secondary);
                }

                @keyframes spotFadeIn { from { opacity: 0; } to { opacity: 1; } }
                @keyframes qlScale { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
            `}</style>
        </div>
    )
}

export default KeyboardShortcuts
