import React, { useRef, useEffect } from 'react'
import { useNotifications } from '../contexts/NotificationContext'

function NotificationCenter() {
    const { notifications, markAsRead, isOpen, setIsOpen } = useNotifications()
    const panelRef = useRef(null)

    // Close when clicking outside
    useEffect(() => {
        function handleClickOutside(event) {
            if (panelRef.current && !panelRef.current.contains(event.target) && isOpen) {
                // Check if click was on the trigger button (handled elsewhere usually, but safety check)
                // Actually, simplest is just to close if it's not inside panel
                // We rely on the toggle button stopping propagation if it's clicked
                setIsOpen(false)
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, [isOpen, setIsOpen]);

    if (!isOpen) return null

    // Group notifications
    const today = new Date().toLocaleDateString()
    const grouped = notifications.reduce((acc, n) => {
        const date = new Date(n.created_at).toLocaleDateString()
        const key = date === today ? 'Today' : date
        if (!acc[key]) acc[key] = []
        acc[key].push(n)
        return acc
    }, {})

    return (
        <div
            ref={panelRef}
            className="notification-center glass-panel"
            style={{
                position: 'fixed',
                top: '38px', // Below Menu Bar
                right: '10px',
                width: '320px',
                height: 'calc(100vh - 140px)', // Leave space for dock
                zIndex: 9000,
                borderRadius: '12px',
                overflow: 'hidden',
                display: 'flex',
                flexDirection: 'column',
                animation: 'slideInRight 0.25s ease-out',
                border: '1px solid var(--glass-border)',
                background: 'var(--glass-bg)',
                backdropFilter: 'blur(20px)',
                boxShadow: '0 20px 50px rgba(0,0,0,0.3)'
            }}
        >
            {/* Header */}
            <div style={{
                padding: '12px 16px',
                borderBottom: '1px solid var(--glass-border)',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
            }}>
                <span style={{ fontWeight: 600, fontSize: '13px', color: 'var(--text-primary)' }}>Notifications</span>
                {notifications.some(n => !n.is_read) && (
                    <button
                        onClick={() => markAsRead()}
                        style={{
                            background: 'none', border: 'none',
                            color: 'var(--accent-color)',
                            fontSize: '11px', fontWeight: 500,
                            cursor: 'pointer'
                        }}
                    >
                        Mark all as read
                    </button>
                )}
            </div>

            {/* List */}
            <div style={{ flex: 1, overflowY: 'auto', padding: '0 10px' }}>
                {Object.keys(grouped).length === 0 ? (
                    <div style={{ padding: '40px 20px', textAlign: 'center', color: 'var(--text-secondary)', fontSize: '13px' }}>
                        No notifications
                    </div>
                ) : (
                    Object.entries(grouped).map(([date, items]) => (
                        <div key={date}>
                            <h4 style={{
                                margin: '16px 6px 8px',
                                fontSize: '11px',
                                fontWeight: 600,
                                color: 'var(--text-secondary)',
                                textTransform: 'uppercase',
                                letterSpacing: '0.5px'
                            }}>{date}</h4>

                            {items.map(n => (
                                <div
                                    key={n.id}
                                    onClick={() => markAsRead(n.id)}
                                    className="notification-item"
                                    style={{
                                        padding: '10px',
                                        marginBottom: '6px',
                                        borderRadius: '8px',
                                        background: n.is_read ? 'transparent' : 'rgba(var(--accent-rgb), 0.1)',
                                        cursor: 'pointer',
                                        transition: 'background 0.2s',
                                        position: 'relative'
                                    }}
                                >
                                    {/* Unread Dot */}
                                    {!n.is_read && (
                                        <div style={{
                                            position: 'absolute', left: '4px', top: '16px',
                                            width: '6px', height: '6px', borderRadius: '50%',
                                            background: 'var(--accent-color)'
                                        }}></div>
                                    )}

                                    <div style={{ paddingLeft: !n.is_read ? '14px' : '0' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2px' }}>
                                            <span style={{ fontSize: '13px', fontWeight: 500, color: 'var(--text-primary)' }}>{n.title}</span>
                                            <span style={{ fontSize: '10px', color: 'var(--text-secondary)' }}>
                                                {new Date(n.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </span>
                                        </div>
                                        <p style={{ fontSize: '12px', color: 'var(--text-secondary)', margin: 0, lineHeight: '1.4' }}>
                                            {n.message}
                                        </p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ))
                )}
            </div>

            <style>{`
                .notification-center {
                    position: fixed;
                    top: 50px;
                    right: 16px;
                    width: 360px;
                    height: calc(100vh - 140px);
                    z-index: 9000;
                    border-radius: 16px;
                    overflow: hidden;
                    display: flex;
                    flex-direction: column;
                    animation: ncSlideIn 0.3s var(--ease-out-expo);
                    border: var(--border-layer-3);
                    background: var(--glass-layer-3);
                    backdrop-filter: var(--blur-layer-3);
                    -webkit-backdrop-filter: var(--blur-layer-3);
                    box-shadow: var(--shadow-layer-4);
                }
                /* Inner rim light */
                .notification-center::after {
                    content: ''; position: absolute; inset: 0; border-radius: 16px; padding: 1px;
                    background: linear-gradient(180deg, rgba(255,255,255,0.15) 0%, transparent 50%);
                    -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
                    -webkit-mask-composite: xor; mask-composite: exclude; pointer-events: none;
                }

                @keyframes ncSlideIn {
                    from { transform: translateX(20px); opacity: 0; }
                    to { transform: translateX(0); opacity: 1; }
                }

                .notification-item {
                    transition: all 0.2s;
                }
                .notification-item:hover {
                    background: var(--surface-hover) !important;
                    transform: scale(0.99);
                }
                
                /* Custom Scrollbar for this panel */
                div::-webkit-scrollbar { width: 4px; }
                div::-webkit-scrollbar-track { background: transparent; }
                div::-webkit-scrollbar-thumb { background: rgba(128,128,128,0.2); border-radius: 4px; }
            `}</style>
        </div>
    )
}

export default NotificationCenter
