import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'

/**
 * Formation Dashboard Widgets
 * 5 widgets per PRD Section 5.3:
 * 1. Report Submission Status (heatmap grid)
 * 2. Engagement Trend (bar/visual)
 * 3. Pastoral Concerns Feed (scrollable list)
 * 4. Formation Evidence Highlights (card feed)
 * 5. Checkpoint Status (status cards)
 */
function FormationWidgets({ campus }) {
    const navigate = useNavigate()
    const [data, setData] = useState(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        loadData()
    }, [campus])

    const loadData = async () => {
        setLoading(true)
        try {
            const params = new URLSearchParams()
            if (campus) params.append('celebration_point', campus)
            const res = await fetch(`/api/formation-dashboard?${params}`)
            const json = await res.json()
            if (json.success) setData(json)
        } catch { /* ignore */ }
        setLoading(false)
    }

    if (loading) return (
        <div style={{ textAlign: 'center', padding: 40, color: 'var(--text-secondary)' }}>
            Loading formation data...
        </div>
    )

    if (!data) return null

    const { submissionStatus, engagementTrend, pastoralConcerns, formationEvidence, checkpointStatus } = data

    // --- No formation data at all ---
    const hasAnyData = submissionStatus.length > 0 || engagementTrend.length > 0 || pastoralConcerns.length > 0
    if (!hasAnyData) return null

    return (
        <div style={{ marginTop: 24 }}>
            {/* Section Header */}
            <h2 style={{ fontSize: 17, fontWeight: 700, color: 'var(--text-primary)', marginBottom: 16, display: 'flex', alignItems: 'center', gap: 8 }}>
                <span style={{
                    width: 28, height: 28, borderRadius: 8, display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', fontSize: 14
                }}>🌱</span>
                Formation Layer
            </h2>

            {/* Top row: Submission Status + Engagement Trend */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 16 }}>
                {/* Widget 1: Report Submission Status */}
                <div style={glassCard} onClick={() => navigate('/weekly-reports')} className="formation-widget">
                    <div style={widgetHeader}>
                        <span style={widgetTitle}>📊 Report Submissions</span>
                        <span style={{ fontSize: 11, color: 'var(--text-secondary)' }}>{submissionStatus.length} groups</span>
                    </div>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginTop: 10 }}>
                        {submissionStatus.map(g => {
                            const color = g.total_reports > 0
                                ? (g.latest_week >= 1 ? '#34C759' : '#FF9500')
                                : '#FF3B30'
                            return (
                                <div key={g.id} title={`${g.group_code} — ${g.name}\n${g.total_reports} reports, latest: Week ${g.latest_week || '—'}`}
                                    style={{
                                        width: 36, height: 36, borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        background: `${color}18`, border: `1px solid ${color}33`, fontSize: 10, fontWeight: 700, color,
                                        cursor: 'pointer', transition: 'transform 0.15s'
                                    }}
                                    onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.15)'}
                                    onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
                                >
                                    {g.group_code.slice(-3)}
                                </div>
                            )
                        })}
                    </div>
                    <div style={{ display: 'flex', gap: 12, marginTop: 10, fontSize: 10, color: 'var(--text-secondary)' }}>
                        <span><span style={{ color: '#34C759' }}>●</span> Submitted</span>
                        <span><span style={{ color: '#FF9500' }}>●</span> Pending</span>
                        <span><span style={{ color: '#FF3B30' }}>●</span> No reports</span>
                    </div>
                </div>

                {/* Widget 2: Engagement Trend */}
                <div style={glassCard} onClick={() => navigate('/weekly-reports')} className="formation-widget">
                    <div style={widgetHeader}>
                        <span style={widgetTitle}>📈 Engagement Trend</span>
                        <span style={{ fontSize: 11, color: 'var(--text-secondary)' }}>{engagementTrend.length} weeks</span>
                    </div>
                    {engagementTrend.length > 0 ? (
                        <div style={{ marginTop: 10 }}>
                            {/* Mini bar chart */}
                            <div style={{ display: 'flex', alignItems: 'flex-end', gap: 4, height: 80 }}>
                                {engagementTrend.map(w => {
                                    const maxScore = 3
                                    const height = Math.max(10, (w.avg_score / maxScore) * 70)
                                    const color = w.avg_score >= 2.5 ? '#34C759' : w.avg_score >= 1.5 ? '#FF9500' : '#FF3B30'
                                    return (
                                        <div key={w.week_number} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 }}
                                            title={`Week ${w.week_number}: ${w.avg_score}/3.0\nHigh: ${w.high_count}, Med: ${w.medium_count}, Low: ${w.low_count}`}
                                        >
                                            <div style={{
                                                width: '100%', maxWidth: 28, height, borderRadius: '6px 6px 2px 2px',
                                                background: `linear-gradient(to top, ${color}88, ${color})`,
                                                transition: 'height 0.3s'
                                            }} />
                                            <span style={{ fontSize: 9, color: 'var(--text-secondary)', marginTop: 3 }}>W{w.week_number}</span>
                                        </div>
                                    )
                                })}
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 6, fontSize: 10, color: 'var(--text-secondary)' }}>
                                <span>Low (1.0)</span>
                                <span>High (3.0)</span>
                            </div>
                        </div>
                    ) : (
                        <div style={{ padding: 20, textAlign: 'center', fontSize: 12, color: 'var(--text-secondary)' }}>No engagement data yet</div>
                    )}
                </div>
            </div>

            {/* Bottom row: Pastoral Concerns + Formation Evidence + Checkpoint Status */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 16 }}>
                {/* Widget 3: Pastoral Concerns Feed */}
                <div style={{ ...glassCard, maxHeight: 260, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                    <div style={widgetHeader}>
                        <span style={widgetTitle}>🙏 Pastoral Concerns</span>
                        <span style={{ fontSize: 11, color: '#FF9500' }}>{pastoralConcerns.length}</span>
                    </div>
                    <div style={{ flex: 1, overflowY: 'auto', marginTop: 8 }}>
                        {pastoralConcerns.length > 0 ? pastoralConcerns.map(c => (
                            <div key={c.id} onClick={() => navigate('/weekly-reports')}
                                style={{
                                    padding: '8px 0', borderBottom: '1px solid rgba(255,255,255,0.04)',
                                    cursor: 'pointer', transition: 'background 0.15s'
                                }}
                            >
                                <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginBottom: 3 }}>
                                    {c.group_code} · Week {c.week_number} · {c.facilitator_name}
                                </div>
                                <div style={{
                                    fontSize: 12, color: 'var(--text-primary)', lineHeight: 1.4,
                                    display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden'
                                }}>
                                    {c.pastoral_concerns}
                                </div>
                            </div>
                        )) : (
                            <div style={{ padding: 16, textAlign: 'center', fontSize: 12, color: 'var(--text-secondary)' }}>No concerns flagged</div>
                        )}
                    </div>
                </div>

                {/* Widget 4: Formation Evidence Highlights */}
                <div style={{ ...glassCard, maxHeight: 260, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                    <div style={widgetHeader}>
                        <span style={widgetTitle}>🌱 Formation Evidence</span>
                        <span style={{ fontSize: 11, color: '#34C759' }}>{formationEvidence.length}</span>
                    </div>
                    <div style={{ flex: 1, overflowY: 'auto', marginTop: 8 }}>
                        {formationEvidence.length > 0 ? formationEvidence.map(e => (
                            <div key={e.id} onClick={() => navigate('/weekly-reports')}
                                style={{
                                    padding: '8px 0', borderBottom: '1px solid rgba(255,255,255,0.04)',
                                    cursor: 'pointer'
                                }}
                            >
                                <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginBottom: 3 }}>
                                    {e.group_code} · Week {e.week_number} · {e.facilitator_name}
                                </div>
                                <div style={{
                                    fontSize: 12, color: 'var(--text-primary)', lineHeight: 1.4,
                                    display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden'
                                }}>
                                    {e.formation_evidence}
                                </div>
                            </div>
                        )) : (
                            <div style={{ padding: 16, textAlign: 'center', fontSize: 12, color: 'var(--text-secondary)' }}>No evidence reported</div>
                        )}
                    </div>
                </div>

                {/* Widget 5: Checkpoint Status */}
                <div style={{ ...glassCard, maxHeight: 260, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                    <div style={widgetHeader}>
                        <span style={widgetTitle}>🎯 Checkpoint Status</span>
                    </div>
                    {checkpointStatus.length > 0 ? (
                        <div style={{ marginTop: 8, flex: 1, overflowY: 'auto' }}>
                            {[4, 8, 13].map(week => {
                                const weekCheckpoints = checkpointStatus.filter(c => c.checkpoint_week === week)
                                if (weekCheckpoints.length === 0) return null
                                const reviewed = weekCheckpoints.filter(c => c.status === 'reviewed').length
                                const completed = weekCheckpoints.filter(c => c.status === 'completed').length
                                const pending = weekCheckpoints.filter(c => c.status === 'pending').length
                                return (
                                    <div key={week} onClick={() => navigate('/checkpoints')}
                                        style={{
                                            padding: '8px 0', borderBottom: '1px solid rgba(255,255,255,0.04)',
                                            cursor: 'pointer'
                                        }}>
                                        <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-primary)', marginBottom: 4 }}>
                                            Week {week}
                                        </div>
                                        <div style={{ display: 'flex', gap: 8, fontSize: 10 }}>
                                            {reviewed > 0 && <span style={{ color: '#34C759' }}>✅ {reviewed} reviewed</span>}
                                            {completed > 0 && <span style={{ color: '#007AFF' }}>✓ {completed} completed</span>}
                                            {pending > 0 && <span style={{ color: '#FF9500' }}>⏳ {pending} pending</span>}
                                        </div>
                                    </div>
                                )
                            })}
                        </div>
                    ) : (
                        <div style={{ padding: 16, textAlign: 'center', fontSize: 12, color: 'var(--text-secondary)' }}>
                            No checkpoints generated yet
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

// --- Styles ---
// --- Styles ---
const glassCard = {
    background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-2)',
    border: 'var(--border-layer-2)', borderRadius: 16, padding: 20,
    cursor: 'pointer', transition: 'transform 0.2s var(--ease-spring), box-shadow 0.2s var(--ease-spring), background 0.2s',
    boxShadow: 'var(--shadow-layer-2)'
}
const widgetHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }
const widgetTitle = { fontSize: 14, fontWeight: 600, color: 'var(--text-primary)', letterSpacing: '0.01em' }

export default FormationWidgets
