import { useState, useEffect } from 'react'
import { useAuth } from '../contexts/AuthContext'

function Login() {
    const { login } = useAuth()
    const [username, setUsername] = useState('')
    const [password, setPassword] = useState('')
    const [error, setError] = useState('')
    const [loading, setLoading] = useState(false)
    const [time, setTime] = useState(new Date())
    const [savedUser, setSavedUser] = useState(null)
    const [isPasswordVisible, setIsPasswordVisible] = useState(false)

    useEffect(() => {
        const timer = setInterval(() => setTime(new Date()), 1000)

        // Check for saved user
        const saved = localStorage.getItem('last_user')
        if (saved) {
            try {
                const user = JSON.parse(saved)
                setSavedUser(user)
                setUsername(user.username || '')
                // If we have a saved user, we default to showing password input? 
                // macOS Behavior: Click avatar -> Password. 
                // Let's assume interaction starts with "User Selected".
                setIsPasswordVisible(true)
            } catch (e) {
                console.error('Failed to parse saved user', e)
            }
        } else {
            // No saved user, maybe show generic input immediately
            setIsPasswordVisible(true)
        }

        return () => clearInterval(timer)
    }, [])

    const handleSubmit = async (e) => {
        e.preventDefault()
        setError('')
        setLoading(true)

        const result = await login(username, password)

        if (!result.success) {
            setError(result.message)
            setLoading(false)
        } else {
            if (result.user) {
                // Performance Optimization: Warm up cache
                fetch('/api/data/students').catch(console.error)

                localStorage.setItem('last_user', JSON.stringify({
                    username: result.user.username,
                    name: result.user.name,
                    profile_image: result.user.profile_image
                }))
            }
        }
    }

    const formatTime = (date) => {
        return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: false })
    }

    const formatDate = (date) => {
        return date.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })
    }

    return (
        <div className="tahoe-login-container">
            {/* Top: Clock Section */}
            <div className="tahoe-clock-container">
                <div className="tahoe-clock">{formatTime(time)}</div>
                <div className="tahoe-date">{formatDate(time)}</div>
            </div>

            {/* Bottom: Auth Section */}
            <div className="tahoe-auth-container">
                {/* Avatar */}
                <div className="login-avatar-large">
                    {savedUser && savedUser.profile_image ? (
                        <img src={savedUser.profile_image} alt="Avatar" />
                    ) : (
                        <svg width="60" height="60" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" style={{ opacity: 0.8 }}>
                            <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path>
                            <circle cx="12" cy="7" r="4"></circle>
                        </svg>
                    )}
                </div>

                {/* Username Display */}
                <div className="tahoe-username">
                    {savedUser ? (savedUser.name || savedUser.username) : (username || 'Other User')}
                </div>

                {/* Error Message */}
                {error && (
                    <div style={{
                        color: '#fca5a5', fontSize: '13px', marginBottom: '12px',
                        textShadow: '0 1px 2px rgba(0,0,0,0.5)'
                    }}>
                        {error}
                    </div>
                )}

                {/* Password Input Pill */}
                <form onSubmit={handleSubmit} style={{ width: '100%' }}>
                    {!savedUser && (
                        <div className="tahoe-password-pill" style={{ marginBottom: '10px' }}>
                            <input
                                type="text"
                                className="tahoe-input-transparent"
                                placeholder="Username"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                required
                                autoFocus={!savedUser}
                            />
                        </div>
                    )}

                    <div className="tahoe-password-pill">
                        <input
                            type="password"
                            className="tahoe-input-transparent"
                            placeholder="Enter Password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            autoFocus={!!savedUser}
                            autoComplete="current-password"
                        />
                        <button type="submit" className="tahoe-submit-btn" disabled={loading}>
                            {loading ? (
                                <div className="spinner" style={{ width: '16px', height: '16px', borderWidth: '2px' }}></div>
                            ) : (
                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <line x1="5" y1="12" x2="19" y2="12"></line>
                                    <polyline points="12 5 19 12 12 19"></polyline>
                                </svg>
                            )}
                        </button>
                    </div>
                </form>

                <div style={{ marginTop: '40px', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
                    <div style={{ fontSize: '12px', color: 'rgba(255,255,255,0.4)', fontWeight: 500 }}>
                        Enter Password
                    </div>
                    {savedUser && (
                        <button
                            className="tahoe-secondary-action"
                            onClick={() => {
                                setSavedUser(null)
                                setUsername('')
                                setPassword('')
                            }}
                        >
                            Switch User
                        </button>
                    )}
                </div>

            </div>

            <div style={{ position: 'absolute', bottom: '20px', fontSize: '11px', color: 'rgba(255,255,255,0.3)' }}>
                Watoto Church © 2026
            </div>
        </div>
    )
}

export default Login
