import React from 'react';

const HealthRing = ({ score, size = 32, strokeWidth = 1.5 }) => {
    // Score is 'critical', 'attention', 'healthy'
    // We can map these to percentage or just color rings
    // Or we can take a numeric score if available. 
    // For now, let's map status to a visual ring.

    // Healthy = 100% green
    // Attention = 75% yellow
    // Critical = 40% red

    let color = 'var(--system-green)';
    let percent = 100;

    if (score === 'attention') {
        color = 'var(--system-yellow)';
        percent = 75;
    } else if (score === 'critical') {
        color = 'var(--system-red)';
        percent = 40;
    } else if (typeof score === 'number') {
        percent = score;
        if (percent < 50) color = 'var(--system-red)';
        else if (percent < 80) color = 'var(--system-yellow)';
        else color = 'var(--system-green)';
    }

    const radius = (size - strokeWidth) / 2;
    const circumference = radius * 2 * Math.PI;
    // Calculation: offset = C - (percent / 100) * C
    const offset = circumference - (percent / 100) * circumference;

    return (
        <div style={{ position: 'relative', width: size, height: size, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width={size} height={size} style={{ transform: 'rotate(-90deg)' }}>
                {/* Background Ring */}
                <circle
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    fill="none"
                    stroke="rgba(255,255,255,0.1)"
                    strokeWidth={strokeWidth}
                />
                {/* Progress Ring */}
                <circle
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    fill="none"
                    stroke={color}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    style={{ transition: 'stroke-dashoffset 0.5s ease' }}
                />
            </svg>
            {/* Optional Icon/Dot in center? or just leave as ring */}
        </div>
    );
};

export default HealthRing;
