import { useEffect } from 'react'
import { Routes, Route, Navigate } from 'react-router-dom'
import Login from './components/Login'
import Layout from './components/Layout'
import Dashboard from './pages/Dashboard'
import Students from './pages/Students'
import Admin from './pages/Admin'
import AuditLogs from './pages/AuditLogs'
import Reports from './pages/Reports'
import ImportTool from './pages/ImportTool'
import FormationGroups from './pages/FormationGroups'
import WeeklyReports from './pages/WeeklyReports'
import Settings from './pages/Settings'
import Checkpoints from './pages/Checkpoints'
import TechSupportPage from './pages/TechSupport'
import ReportExport from './pages/ReportExport'

import Toast from './components/Toast'
import { WallpaperProvider } from './contexts/WallpaperContext'
import { useAuth } from './contexts/AuthContext'
import { SettingsProvider } from './contexts/SettingsContext'
import { NotificationProvider } from './contexts/NotificationContext'
import NotificationCenter from './components/NotificationCenter'
import { SpotlightProvider } from './contexts/SpotlightContext'
import SpotlightSearch from './components/SpotlightSearch'
import KeyboardShortcuts from './components/KeyboardShortcuts'
import Stickies from './components/Stickies'
import Handoff from './components/Handoff'
import Launchpad from './components/Launchpad'
import MissionControl from './components/MissionControl'

// Celebration Points List
export const CELEBRATION_POINTS = [
    'Bbira',
    'Bugolobi',
    'Bweyogerere',
    'Downtown',
    'Entebbe',
    'Nakwero',
    'Gulu',
    'Jinja',
    'Juba',
    'Kansanga',
    'Kyengera',
    'Laminadera',
    'Lubowa',
    'Mbarara',
    'Mukono',
    'Nansana',
    'Ntinda',
    'Online',
    'Suubi'
]

function App() {
    const { user, loading, toasts } = useAuth()

    // Performance Optimization: Warm up cache immediately when authenticated
    useEffect(() => {
        if (user) {
            // Fire and forget - just to get the server cache warm
            fetch('/api/data/students').catch(err => console.debug('Cache warmup background fetch', err))
        }
    }, [user])

    if (loading) {
        return (
            <div className="login-container">
                <div className="spinner"></div>
            </div>
        )
    }

    return (
        <WallpaperProvider>
            <SettingsProvider>
                <NotificationProvider>
                    <SpotlightProvider>
                        <div className="mesh-background"></div>
                        <NotificationCenter />
                        <SpotlightSearch />
                        <KeyboardShortcuts />
                        <Stickies />
                        <Handoff />
                        <Launchpad />
                        <MissionControl />
                        <Routes>
                            <Route
                                path="/login"
                                element={user ? <Navigate to="/dashboard" /> : <Login />}
                            />

                            {/* Protected Routes wrapped in Layout */}
                            {user && (
                                <Route element={<Layout />}>
                                    <Route path="/dashboard" element={<Dashboard />} />
                                    <Route path="/students" element={(['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'TechSupport'].includes(user.role)) ? <Students /> : <Navigate to="/dashboard" />} />
                                    <Route path="/admin" element={(['Admin', 'TechSupport'].includes(user.role)) ? <Admin /> : <Navigate to="/dashboard" />} />
                                    <Route path="/audit" element={(['Admin', 'LeadershipTeam'].includes(user.role)) ? <AuditLogs /> : <Navigate to="/dashboard" />} />
                                    <Route path="/reports" element={(['Admin', 'LeadershipTeam', 'Pastor'].includes(user.role)) ? <Reports /> : <Navigate to="/dashboard" />} />
                                    <Route path="/import" element={(['Admin', 'Coordinator'].includes(user.role)) ? <ImportTool /> : <Navigate to="/dashboard" />} />
                                    <Route path="/groups" element={(['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator'].includes(user.role)) ? <FormationGroups /> : <Navigate to="/dashboard" />} />
                                    <Route path="/weekly-reports" element={['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator', 'TechSupport'].includes(user.role) ? <WeeklyReports /> : <Navigate to="/dashboard" />} />
                                    <Route path="/settings" element={user.role === 'Admin' ? <Settings /> : <Navigate to="/dashboard" />} />
                                    <Route path="/checkpoints" element={['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator', 'TechSupport'].includes(user.role) ? <Checkpoints /> : <Navigate to="/dashboard" />} />
                                    <Route path="/tech-support" element={['Admin', 'TechSupport'].includes(user.role) ? <TechSupportPage /> : <Navigate to="/dashboard" />} />
                                    <Route path="/exports" element={['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator', 'TechSupport'].includes(user.role) ? <ReportExport /> : <Navigate to="/dashboard" />} />
                                </Route>
                            )}

                            <Route path="*" element={<Navigate to={user ? "/dashboard" : "/login"} />} />
                        </Routes>

                        <Toast toasts={toasts} />
                    </SpotlightProvider>
                </NotificationProvider>
            </SettingsProvider>
        </WallpaperProvider>
    )
}

export default App
