import { useState, useEffect } from 'react'
import { Outlet, useLocation } from 'react-router-dom'
import Dock from './Dock'
import MenuBar from './MenuBar'
import DesktopWidgets from './DesktopWidgets'

function Layout() {
    const [isMinimized, setIsMinimized] = useState(false)
    const location = useLocation()

    // Restore window when navigating to a new route
    useEffect(() => {
        setIsMinimized(false)
    }, [location.pathname])

    return (
        <div className="tahoe-desktop-env">
            {/* Desktop Widgets Layer (Behind Window) */}
            <DesktopWidgets />

            {/* Global Top Bar */}
            <MenuBar />

            {/* Main Application Window (Floating) */}
            <div className={`app-window-frame ${isMinimized ? 'minimized' : ''}`}>
                {/* Traffic Lights for the 'Window' */}
                <div className="window-header-controls">
                    <span className="control red"></span>
                    <span
                        className="control yellow"
                        onClick={() => setIsMinimized(true)}
                        title="Minimize"
                    ></span>
                    <span className="control green"></span>
                </div>

                <div className="main-content-wrapper">
                    <div className="content-scroll-area">
                        <Outlet />
                    </div>
                </div>
            </div>

            {/* macOS Style Dock */}
            <Dock onAppClick={() => setIsMinimized(false)} />

            <style>{`
                .tahoe-desktop-env {
                    height: 100vh;
                    width: 100vw;
                    display: flex;
                    flex-direction: column;
                    overflow: hidden;
                    position: relative;
                }

                .app-window-frame {
                    flex: 1;
                    margin: 40px var(--space-sm) var(--space-xl) var(--space-sm);
                    background: var(--glass-layer-1);
                    backdrop-filter: var(--blur-layer-1);
                    -webkit-backdrop-filter: var(--blur-layer-1);
                    border: var(--border-layer-1);
                    border-radius: var(--radius-window);
                    box-shadow: var(--shadow-layer-2);
                    display: flex;
                    flex-direction: column;
                    overflow: hidden;
                    position: relative;
                    z-index: 10;
                    transition: all var(--duration-system) var(--ease-system);
                    transform-origin: bottom center;
                }

                .app-window-frame.minimized {
                    transform: scale(0.6) translateY(100vh);
                    opacity: 0;
                    pointer-events: none;
                }

                .window-header-controls {
                    height: 40px;
                    display: flex;
                    align-items: center;
                    padding-left: 16px;
                    gap: 8px;
                    border-bottom: 1px solid rgba(255,255,255,0.05);
                    background: rgba(255,255,255,0.02);
                }

                .control {
                    width: 12px;
                    height: 12px;
                    border-radius: 50%;
                    cursor: pointer;
                    position: relative;
                }
                .control:hover::after {
                    content: '';
                    position: absolute;
                    top: 0; left: 0; bottom: 0; right: 0;
                    background: rgba(0,0,0,0.1);
                    border-radius: 50%;
                }
                .control.red { background: #FF5F57; border: 1px solid #E0443E; }
                .control.yellow { background: #FFBD2E; border: 1px solid #DEA123; }
                .control.green { background: #28C840; border: 1px solid #1AAB29; }

                .main-content-wrapper {
                    flex: 1;
                    display: flex;
                    flex-direction: column;
                    background: rgba(0, 0, 0, 0.04);
                    backdrop-filter: blur(4px);
                    -webkit-backdrop-filter: blur(4px);
                    position: relative;
                    overflow: hidden;
                    box-shadow: inset 0 1px 0 rgba(255,255,255,0.04);
                }

                .content-scroll-area {
                    flex: 1;
                    padding: var(--space-lg);
                    overflow-y: auto;
                    scroll-behavior: smooth;
                }
                
                /* Responsive */
                @media (max-width: 768px) {
                    .app-window-frame {
                        margin: 40px var(--space-xs) 90px var(--space-xs);
                    }
                }
            `}</style>
        </div>
    )
}

export default Layout
