import { useState, useEffect } from 'react'

function ProfilePicker({ selectedImage, onSelect }) {
    const [images, setImages] = useState({})
    const [loading, setLoading] = useState(true)
    const [activeCategory, setActiveCategory] = useState(null)

    useEffect(() => {
        fetch('/api/public/profile-images')
            .then(res => res.json())
            .then(data => {
                if (data.success) {
                    setImages(data.images)
                    if (Object.keys(data.images).length > 0) {
                        setActiveCategory(Object.keys(data.images)[0])
                    }
                }
            })
            .catch(err => console.error('Failed to load profile images', err))
            .finally(() => setLoading(false))
    }, [])

    if (loading) return <div className="picker-loading">Loading avatars...</div>

    const categories = Object.keys(images)

    return (
        <div className="profile-picker">
            {/* Horizontal Tabs */}
            <div className="picker-tabs">
                {categories.map(cat => (
                    <button
                        key={cat}
                        onClick={() => setActiveCategory(cat)}
                        className={`picker-tab ${activeCategory === cat ? 'active' : ''}`}
                    >
                        {cat}
                    </button>
                ))}
            </div>

            {/* Image Grid */}
            <div className="picker-grid-container">
                {activeCategory && (
                    <div className="picker-grid">
                        {images[activeCategory].map((img, idx) => (
                            <div
                                key={idx}
                                onClick={() => onSelect(img)}
                                className={`picker-item ${selectedImage === img ? 'active' : ''}`}
                            >
                                <img
                                    src={img}
                                    alt="Avatar"
                                    className="picker-img"
                                    onError={(e) => {
                                        e.target.onerror = null;
                                        e.target.style.display = 'none';
                                        e.target.parentNode.classList.add('error');
                                        e.target.parentNode.innerHTML = '<span>?</span>';
                                    }}
                                />
                                {selectedImage === img && (
                                    <div className="picker-check">
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                            <polyline points="20 6 9 17 4 12"></polyline>
                                        </svg>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <style>{`
                .profile-picker {
                    display: flex; flex-direction: column; height: 320px;
                    border: 1px solid var(--border-layer-2);
                    border-radius: 12px; overflow: hidden;
                    background: var(--glass-layer-1);
                }
                .picker-loading {
                    padding: 20px; text-align: center; color: var(--text-secondary);
                }
                .picker-tabs {
                    display: flex; overflow-x: auto;
                    background: var(--glass-layer-1);
                    border-bottom: 1px solid var(--border-layer-1);
                    padding: 8px 8px; gap: 4px;
                }
                /* Hide scrollbar */
                .picker-tabs::-webkit-scrollbar { display: none; }
                
                .picker-tab {
                    padding: 6px 12px; white-space: nowrap;
                    background: transparent;
                    color: var(--text-secondary);
                    border: 1px solid transparent; border-radius: 8px;
                    font-size: 12px; font-weight: 500; cursor: pointer;
                    transition: all 0.2s;
                }
                .picker-tab:hover {
                    color: var(--text-primary);
                    background: var(--glass-layer-2);
                }
                .picker-tab.active {
                    background: var(--glass-layer-3);
                    color: var(--text-primary);
                    border-color: var(--border-layer-2);
                    box-shadow: var(--shadow-layer-1);
                }

                .picker-grid-container {
                    flex: 1; padding: 16px; overflow-y: auto;
                    background: var(--glass-layer-2);
                }
                .picker-grid {
                    display: grid; grid-template-columns: repeat(auto-fill, minmax(60px, 1fr));
                    gap: 12px;
                }
                .picker-item {
                    aspect-ratio: 1; border-radius: 50%; overflow: hidden; cursor: pointer;
                    border: 3px solid transparent;
                    transition: all 0.2s; position: relative;
                    opacity: 1; background: var(--glass-layer-3);
                }
                .picker-item:hover { transform: scale(1.1); z-index: 2; }
                .picker-item.active {
                    border-color: var(--primary-color);
                    box-shadow: 0 4px 16px rgba(102,126,234,0.3);
                    transform: scale(1.05);
                }
                .picker-img {
                    width: 100%; height: 100%; object-fit: cover;
                }
                .picker-item.error {
                    background: var(--glass-layer-1);
                    display: flex; align-items: center; justify-content: center;
                    color: var(--text-secondary); font-size: 24px;
                }
                .picker-check {
                    position: absolute; inset: 0; background: rgba(0, 0, 0, 0.4);
                    display: flex; align-items: center; justify-content: center;
                }
            `}</style>
        </div>
    )
}

export default ProfilePicker
