import { useState, useEffect } from 'react'


function DesktopWidgets() {
    const [time, setTime] = useState(new Date())

    useEffect(() => {
        const timer = setInterval(() => setTime(new Date()), 1000)
        return () => clearInterval(timer)
    }, [])

    return (
        <div className="desktop-widgets-layer">
            <div className="widget-column">
                {/* Clock Widget */}
                <div className="desktop-widget clock-widget">
                    <div className="clock-face">
                        <div className="time">{time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                        <div className="date">{time.toLocaleDateString([], { weekday: 'long', month: 'long', day: 'numeric' })}</div>
                    </div>
                </div>

                {/* Calendar Widget (Static Mock) */}
                <div className="desktop-widget calendar-widget">
                    <div className="month">{time.toLocaleDateString([], { month: 'long' }).toUpperCase()}</div>
                    <div className="day">{time.getDate()}</div>
                    <div className="weekday">{time.toLocaleDateString([], { weekday: 'long' })}</div>
                </div>

                {/* Quote or Status Widget */}
                <div className="desktop-widget status-widget">
                    <div className="widget-title">Status</div>
                    <div className="status-row">
                        <span className="dot online"></span>
                        <span>System Operational</span>
                    </div>
                    <div className="status-row">
                        <span className="label">Next Class:</span>
                        <span className="value">Tue 18:00</span>
                    </div>
                </div>
            </div>

            <style>{`
                .desktop-widgets-layer {
                    position: fixed;
                    top: 50px; /* Below MenuBar */
                    left: 20px;
                    bottom: 100px; /* Above Dock */
                    width: 300px;
                    z-index: 0; /* Behind App Window */
                    pointer-events: none; /* Let clicks pass through to wallpaper if needed, but widgets usually interactive */
                }

                .widget-column {
                    display: flex;
                    flex-direction: column;
                    gap: 20px;
                }

                .desktop-widget {
                    background: rgba(255, 255, 255, 0.15);
                    backdrop-filter: blur(25px) saturate(180%);
                    -webkit-backdrop-filter: blur(25px) saturate(180%);
                    border-radius: 22px;
                    padding: 20px;
                    color: white;
                    border: 1px solid rgba(255, 255, 255, 0.2);
                    box-shadow: 0 4px 24px rgba(0, 0, 0, 0.1);
                    pointer-events: auto;
                    transition: transform 0.2s;
                }
                
                [data-theme="dark"] .desktop-widget {
                     background: rgba(30, 30, 30, 0.3);
                     border: 1px solid rgba(255, 255, 255, 0.1);
                     box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
                }

                .desktop-widget:hover {
                    transform: scale(1.02);
                }

                /* Clock Widget */
                .clock-widget {
                    text-align: center;
                }
                .clock-widget .time {
                    font-size: 3rem;
                    font-weight: 300;
                    letter-spacing: -1px;
                    line-height: 1;
                }
                .clock-widget .date {
                    font-size: 1rem;
                    opacity: 0.8;
                    margin-top: 5px;
                    font-weight: 500;
                }

                /* Calendar Widget */
                .calendar-widget {
                    display: flex;
                    flex-direction: column;
                    align-items: center;
                    justify-content: center;
                    background: rgba(255, 255, 255, 0.25); /* Lighter for calendar */
                }
                [data-theme="dark"] .calendar-widget { background: rgba(0, 0, 0, 0.4); }

                .calendar-widget .month {
                    font-size: 0.9rem;
                    font-weight: 700;
                    color: #ff3b30; /* macOS Red */
                    margin-bottom: 0;
                }
                .calendar-widget .day {
                    font-size: 3.5rem;
                    font-weight: 400;
                    line-height: 1;
                }
                .calendar-widget .weekday {
                    font-size: 1rem;
                    opacity: 0.7;
                }

                /* Status Widget */
                .status-widget .widget-title {
                    font-size: 0.8rem;
                    text-transform: uppercase;
                    opacity: 0.6;
                    margin-bottom: 10px;
                    letter-spacing: 0.5px;
                }
                .status-row {
                    display: flex;
                    align-items: center;
                    gap: 8px;
                    margin-bottom: 6px;
                    font-size: 0.95rem;
                }
                .dot.online {
                    width: 8px;
                    height: 8px;
                    background: #4cd964;
                    border-radius: 50%;
                    box-shadow: 0 0 8px #4cd964;
                }
                .status-row .label {
                    opacity: 0.7;
                }
                .status-row .value {
                    font-weight: 600;
                }
            `}</style>
        </div>
    )
}

export default DesktopWidgets
