import { useEffect, useState } from 'react'
import {
    Chart as ChartJS,
    CategoryScale,
    LinearScale,
    BarElement,
    Title,
    Tooltip,
    Legend,
    ArcElement,
    PointElement,
    LineElement
} from 'chart.js'
import { Bar, Pie, Line, Doughnut } from 'react-chartjs-2'
import { useSettings } from '../contexts/SettingsContext'

ChartJS.register(
    CategoryScale,
    LinearScale,
    BarElement,
    Title,
    Tooltip,
    Legend,
    ArcElement,
    PointElement,
    LineElement
)

const chartColors = {
    primary: 'rgba(99, 102, 241, 0.8)',
    primaryLight: 'rgba(129, 140, 248, 0.8)',
    success: 'rgba(16, 185, 129, 0.8)',
    warning: 'rgba(245, 158, 11, 0.8)',
    danger: 'rgba(239, 68, 68, 0.8)',
    info: 'rgba(59, 130, 246, 0.8)',
    purple: 'rgba(168, 85, 247, 0.8)',
    orange: 'rgba(249, 115, 22, 0.8)',
}

// Helper to get theme-aware options
const useChartOptions = (themePreference) => {
    const isDark = themePreference === 'dark' ||
        (themePreference === 'auto' && window.matchMedia('(prefers-color-scheme: dark)').matches) ||
        document.documentElement.getAttribute('data-theme') === 'dark'

    const textColor = isDark ? 'rgba(255, 255, 255, 0.7)' : 'rgba(0, 0, 0, 0.7)'
    const gridColor = isDark ? 'rgba(255, 255, 255, 0.1)' : 'rgba(0, 0, 0, 0.06)'
    const tickColor = isDark ? 'rgba(255, 255, 255, 0.5)' : 'rgba(0, 0, 0, 0.5)'

    return {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                labels: {
                    color: textColor,
                    font: { family: 'Plus Jakarta Sans', size: 12 },
                    padding: 12
                }
            }
        },
        scales: {
            x: {
                ticks: { color: tickColor },
                grid: { color: gridColor }
            },
            y: {
                ticks: { color: tickColor },
                grid: { color: gridColor }
            }
        }
    }
}

export function ProgressDistributionChart({ data }) {
    const { theme } = useSettings()
    const options = useChartOptions(theme)

    const chartData = {
        labels: ['0-25%', '26-50%', '51-75%', '76-100%'],
        datasets: [{
            label: 'Students',
            data: data || [0, 0, 0, 0],
            backgroundColor: [
                chartColors.danger,
                chartColors.warning,
                chartColors.info,
                chartColors.success
            ],
            borderRadius: 8
        }]
    }

    return (
        <div className="glass-card chart-card">
            <div className="chart-header">
                <h3 className="chart-title">Progress Distribution</h3>
            </div>
            <div className="chart-container">
                <Bar data={chartData} options={options} />
            </div>
        </div>
    )
}

export function CompletionStatusChart({ data }) {
    const { theme } = useSettings()
    const baseOptions = useChartOptions(theme)

    // Doughnut needs slightly different options (no scales)
    const options = {
        ...baseOptions,
        scales: {},
        plugins: {
            legend: {
                position: 'right',
                labels: baseOptions.plugins.legend.labels
            }
        }
    }

    const chartData = {
        labels: ['Completed', 'In Progress', 'Not Started'],
        datasets: [{
            data: data || [0, 0, 0],
            backgroundColor: [
                chartColors.success,
                chartColors.info,
                chartColors.warning
            ],
            borderColor: theme === 'dark' ? 'rgba(255, 255, 255, 0.1)' : 'rgba(255, 255, 255, 1)',
            borderWidth: 2
        }]
    }

    return (
        <div className="glass-card chart-card">
            <div className="chart-header">
                <h3 className="chart-title">Completion Status</h3>
            </div>
            <div className="chart-container">
                <Doughnut data={chartData} options={options} />
            </div>
        </div>
    )
}

export function CourseProgressChart({ data }) {
    const { theme } = useSettings()
    const baseOptions = useChartOptions(theme)

    const options = {
        ...baseOptions,
        indexAxis: 'y',
        plugins: {
            ...baseOptions.plugins,
            legend: { display: false }
        }
    }

    const chartData = {
        labels: data?.labels || ['Course 1', 'Course 2', 'Course 3'],
        datasets: [{
            label: 'Average Progress %',
            data: data?.values || [0, 0, 0],
            backgroundColor: chartColors.primary,
            borderRadius: 8
        }]
    }

    return (
        <div className="glass-card chart-card">
            <div className="chart-header">
                <h3 className="chart-title">Average Progress per Course</h3>
            </div>
            <div className="chart-container">
                <Bar data={chartData} options={options} />
            </div>
        </div>
    )
}

export function EngagementChart({ data }) {
    const { theme } = useSettings()
    const baseOptions = useChartOptions(theme)

    const options = {
        ...baseOptions,
        plugins: {
            ...baseOptions.plugins,
            legend: { display: false }
        }
    }

    const chartData = {
        labels: data?.labels || ['Week 1', 'Week 2', 'Week 3', 'Week 4'],
        datasets: [{
            label: 'Active Students',
            data: data?.values || [0, 0, 0, 0],
            borderColor: chartColors.primary,
            backgroundColor: 'rgba(99, 102, 241, 0.1)',
            fill: true,
            tension: 0.4,
            pointBackgroundColor: chartColors.primary,
            pointBorderColor: '#fff',
            pointHoverBackgroundColor: '#fff',
            pointHoverBorderColor: chartColors.primary
        }]
    }

    return (
        <div className="glass-card chart-card">
            <div className="chart-header">
                <h3 className="chart-title">Engagement Over Time</h3>
            </div>
            <div className="chart-container">
                <Line data={chartData} options={options} />
            </div>
        </div>
    )
}

function Charts({ chartData }) {
    return (
        <div className="charts-section">
            <ProgressDistributionChart data={chartData?.progressDistribution} />
            <CompletionStatusChart data={chartData?.completionStatus} />
            <CourseProgressChart data={chartData?.courseProgress} />
            <EngagementChart data={chartData?.engagement} />

            <style>{`
                .charts-section {
                    display: grid;
                    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
                    gap: 24px;
                }
                .glass-card.chart-card {
                    background: var(--glass-layer-3);
                    backdrop-filter: var(--blur-layer-3);
                    border: var(--border-layer-3);
                    border-radius: 28px;
                    padding: 24px;
                    box-shadow: var(--shadow-layer-3);
                    transition: transform 0.4s var(--ease-spring-smooth), box-shadow 0.4s var(--ease-spring-smooth);
                }
                .glass-card.chart-card:hover {
                    box-shadow: var(--shadow-layer-4);
                }
                .chart-header {
                    margin-bottom: 20px;
                }
                .chart-title {
                    font-size: 15px;
                    font-weight: 600;
                    color: var(--text-primary);
                    margin: 0;
                    letter-spacing: 0.01em;
                }
                .chart-container {
                    position: relative;
                    height: 250px;
                    width: 100%;
                }
            `}</style>
        </div>
    )
}

export default Charts
